// 1. 获取 Webhook 传来的参数
const input = $input.item.json.body || {};
const language = input.language || 'zh';
const outputLanguage = input.outputLanguage || (language === 'en' ? 'English' : 'Chinese');
// 如果 Webhook 传了 themeImagePrompt 就用传来的，否则用默认的测试提示词
const imagePrompt = input.themeImagePrompt || "cj_vector_style, 扁平矢量插画，粗细均匀的黑色轮廓线，单线风格，2D扁平设计，无渐变，无阴影，低饱和度的平涂色彩、和谐的柔和色调、连贯的配色方案，简化但风格化的背景环境，清晰的环境线稿，非写实扁平插画，角色的符号化表情，干净亲和的美学，沉浸式叙事扁平背景";

const textLanguageRule = language === 'en'
  ? ', no Chinese text, no Chinese characters, English labels only if text is necessary'
  : ', Chinese labels only if text is necessary';


// 2. 生成随机种子
const seed = Math.floor(Math.random() * 1000000000000);

// 3. 构建你的 aa.json 工作流
const workflow = {
  "1": {
    "inputs": {
      "unet_name": "z_image_turbo_bf16.safetensors",
      "weight_dtype": "default"
    },
    "class_type": "UNETLoader"
  },
  "2": {
    "inputs": {
      "vae_name": "ae.safetensors"
    },
    "class_type": "VAELoader"
  },
  "3": {
    "inputs": {
      "clip_name": "qwen_3_4b.safetensors",
      "type": "lumina2",
      "device": "default"
    },
    "class_type": "CLIPLoader"
  },
  "4": {
    "inputs": {
      "shift": 3,
      "model": [ "1", 0 ]
    },
    "class_type": "ModelSamplingAuraFlow"
  },
  "5": {
    "inputs": {
      "width": 1968,
      "height": 1152,
      "batch_size": 1
    },
    "class_type": "EmptySD3LatentImage"
  },
  "7": {
    "inputs": {
      "text": "blurry, 3d, realistic, complex textures, bad anatomy, deformed, shadows, gradients",
      "clip": [ "3", 0 ]
    },
    "class_type": "CLIPTextEncode"
  },
  "101": {
    "inputs": {
      "lora_name": "poppy.safetensors",
      "strength_model": 0.8,
      "strength_clip": 1,
      "model": [ "4", 0 ],
      "clip": [ "3", 0 ]
    },
    "class_type": "LoraLoader"
  },
  "102": {
    "inputs": {
      "text": `${imagePrompt}${textLanguageRule}`, // <--- 动态替换为 Webhook 参数
      "clip": [ "101", 1 ]
    },
    "class_type": "CLIPTextEncode"
  },
  "103": {
    "inputs": {
      "seed": seed, // <--- 动态替换为随机种子
      "steps": 20,
      "cfg": 1.5,
      "sampler_name": "euler",
      "scheduler": "simple",
      "denoise": 1,
      "model": [ "101", 0 ],
      "positive": [ "102", 0 ],
      "negative": [ "7", 0 ],
      "latent_image": [ "5", 0 ]
    },
    "class_type": "KSampler"
  },
  "104": {
    "inputs": {
      "samples": [ "103", 0 ],
      "vae": [ "2", 0 ]
    },
    "class_type": "VAEDecode"
  },
  "105": {
    "inputs": {
      "filename_prefix": "Asset_Poppy",
      "images": [ "104", 0 ]
    },
    "class_type": "SaveImage"
  }
};

// 4. 【关键修复】不要使用 JSON.stringify！并将 workflow 包裹在 prompt 字段中
return { 
  comfyuiPayload: {
    "prompt": workflow
  }
};

const promptId = $input.item.json.prompt_id;
const comfyUrl = "https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com";
const maxAttempts = 600;

for (let i = 0; i < maxAttempts; i++) {
  await new Promise(r => setTimeout(r, 3000));
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${comfyUrl}/history/${promptId}`,
      json: true
    });

    const taskData = Object.values(res)[0];

    if (taskData && taskData.outputs) {
      let images = [];
      // 动态遍历所有 output 节点，寻找里面包含 images 数组的节点
      for (const nodeId in taskData.outputs) {
        if (taskData.outputs[nodeId].images && taskData.outputs[nodeId].images.length > 0) {
          images = taskData.outputs[nodeId].images;
          break; // 找到图片就立刻停止遍历
        }
      }

      // 如果找到了图片，就拼接 URL 并返回
      if (images.length > 0) {
        const img = images[0];
        const imageUrl = `${comfyUrl}/view?filename=${img.filename}&subfolder=${img.subfolder || ''}&type=${img.type || 'output'}`;
        return { themeImageUrl: imageUrl };
      }
    }

    if (taskData?.status?.status_str === 'error') {
      return { themeImageUrl: null, error: '图片生成失败(ComfyUI内部报错)' };
    }
  } catch (e) {
    console.log("轮询报错，继续重试:", e.message);
  }
}

return { themeImageUrl: null, error: '图片生成超时' };
